// CF04 WF_COMPETITOR_MONITOR — normalize triggers, scope the project list.
// Triggers:
//   - Schedule (daily 06:00 UTC): no payload, scope = all projects with active competitors
//   - Webhook POST /webhook/competitor/monitor/run: optional { project_id, force }
// Output: one item per project to process, with context flags.
// Global fetch + $env per MEMORY.md (n8n 2.8.4 task runner compat).

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || {};
const projectIdFilter = payload.project_id || null;
const force = payload.force === true;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Determine run mode — Sunday = weekly synthesis day (UTC)
const now = new Date();
const isSunday = now.getUTCDay() === 0;
const runWeeklySynthesis = isSunday || payload.run_weekly_synthesis === true;

// Load distinct project_ids from active competitor_channels, filtered if requested
let channelUrl = `${supabaseUrl}/rest/v1/competitor_channels?is_active=eq.true&select=project_id`;
if (projectIdFilter) channelUrl += `&project_id=eq.${projectIdFilter}`;

const chRes = await fetch(channelUrl, { method: 'GET', headers: sbHeaders });
if (!chRes.ok) {
  throw new Error(`Fetch competitor_channels failed: HTTP ${chRes.status}: ${await chRes.text()}`);
}
const channelRows = await chRes.json();
const projectIds = Array.from(new Set((channelRows || []).map(r => r.project_id).filter(Boolean)));

if (projectIds.length === 0) {
  return [{
    json: {
      skipped: true,
      reason: projectIdFilter
        ? `No active competitor_channels for project ${projectIdFilter}`
        : 'No active competitor_channels in any project',
      via_webhook: viaWebhook,
      run_weekly_synthesis: runWeeklySynthesis
    }
  }];
}

// Emit one item per project; downstream Code node processes sequentially with inter-project batching.
return projectIds.map(pid => ({
  json: {
    project_id: pid,
    force,
    via_webhook: viaWebhook,
    run_weekly_synthesis: runWeeklySynthesis,
    triggered_at: now.toISOString()
  }
}));

// CF04 per-project processor.
// For one project: fetch active channels -> per-channel new-video detection ->
// outlier scoring -> topic-match -> insert competitor_videos + competitor_alerts ->
// update competitor_channels stats.
//
// Inline exponential backoff (1s -> 2s -> 4s -> 8s, max 4 attempts, 30s cap)
// for YouTube + Supabase calls. YouTube quota exhaustion -> graceful exit.
// Per-channel failures don't abort the run.

const data = $input.item.json;
if (data.skipped) return $input.item;

const projectId = data.project_id;
const runStart = Date.now();

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const ytKey = $env.YOUTUBE_API_KEY;

const sleep = (ms) => new Promise(r => setTimeout(r, ms));
let quotaExhausted = false;

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  let lastStatus = 0;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      lastStatus = res.status;
      if (res.ok) {
        return { ok: true, json: await res.json(), status: res.status, attempts: attempt };
      }
      const body = await res.text();
      if (res.status === 403 && /quotaExceeded|dailyLimitExceeded/i.test(body)) {
        return { ok: false, quota: true, status: res.status, error: body, attempts: attempt };
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) {
      const delay = Math.min(1000 * Math.pow(2, attempt - 1), 30000);
      await sleep(delay);
    }
  }
  return { ok: false, status: lastStatus, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

// ISO 8601 duration (PT1H2M3S) -> seconds. Robust against weird inputs.
function parseIsoDuration(s) {
  if (!s || typeof s !== 'string') return 0;
  const m = s.match(/^PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?$/);
  if (!m) return 0;
  const h = parseInt(m[1] || '0', 10);
  const min = parseInt(m[2] || '0', 10);
  const sec = parseInt(m[3] || '0', 10);
  return h * 3600 + min * 60 + sec;
}

function normalizeTitle(s) {
  return String(s || '').toLowerCase().replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
}

// 1. Fetch active competitor channels for this project
const chUrl = `${supabaseUrl}/rest/v1/competitor_channels?project_id=eq.${projectId}&is_active=eq.true&select=id,channel_id,channel_name,channel_handle,uploads_playlist_id,avg_views_30d,avg_views_90d,total_view_count,total_video_count,consecutive_fetch_failures&order=last_checked_at.asc.nullsfirst`;
const chRes = await fetch(chUrl, { method: 'GET', headers: sbHeaders });
if (!chRes.ok) {
  return {
    json: {
      project_id: projectId,
      error: `Fetch channels failed: HTTP ${chRes.status}: ${(await chRes.text()).slice(0, 200)}`,
      via_webhook: data.via_webhook,
      run_weekly_synthesis: data.run_weekly_synthesis
    }
  };
}
const channels = await chRes.json();

if (!channels || channels.length === 0) {
  return {
    json: {
      project_id: projectId,
      channels_processed: 0,
      videos_inserted: 0,
      alerts_created: 0,
      quota_exhausted: false,
      skipped_reason: 'No active channels',
      via_webhook: data.via_webhook,
      run_weekly_synthesis: data.run_weekly_synthesis
    }
  };
}

// 2. Fetch project topics for topic-match detection (substring check, no Claude in daily path)
const topicsRes = await fetch(`${supabaseUrl}/rest/v1/topics?project_id=eq.${projectId}&status=in.(pending,approved,scripting,audio,images,video,assembly,review)&select=id,seo_title,original_title`, { method: 'GET', headers: sbHeaders });
const topicCorpus = topicsRes.ok ? (await topicsRes.json()).map(t => ({
  id: t.id,
  normalized: normalizeTitle(t.seo_title || t.original_title)
})).filter(t => t.normalized.length >= 8) : [];

let totalVideosInserted = 0;
let totalAlertsCreated = 0;
let channelsProcessed = 0;
const channelBatchSize = 5;

for (let i = 0; i < channels.length; i += channelBatchSize) {
  if (quotaExhausted) break;
  const batch = channels.slice(i, i + channelBatchSize);

  for (const ch of batch) {
    if (quotaExhausted) break;
    const channelStart = Date.now();
    let channelFailed = false;
    let channelError = null;

    try {
      // 2a. channels.list -> statistics + uploads playlist
      const chInfoUrl = `https://www.googleapis.com/youtube/v3/channels?part=statistics,contentDetails&id=${ch.channel_id}&key=${ytKey}`;
      const chInfo = await fetchWithRetry(chInfoUrl, { method: 'GET' }, 'yt_channels');
      if (chInfo.quota) { quotaExhausted = true; break; }
      if (!chInfo.ok) { channelFailed = true; channelError = chInfo.error; }

      let uploadsPlaylistId = ch.uploads_playlist_id;
      let statsPatch = {};
      if (chInfo.ok) {
        const item = (chInfo.json?.items || [])[0];
        if (item) {
          uploadsPlaylistId = item.contentDetails?.relatedPlaylists?.uploads || uploadsPlaylistId;
          const subCount = parseInt(item.statistics?.subscriberCount || '0', 10);
          const totalViews = parseInt(item.statistics?.viewCount || '0', 10);
          const totalVideos = parseInt(item.statistics?.videoCount || '0', 10);
          statsPatch = {
            subscriber_count: subCount || null,
            total_video_count: totalVideos || null,
            total_view_count: totalViews || null,
            uploads_playlist_id: uploadsPlaylistId || null,
            avg_views_per_video: (totalVideos > 0) ? (totalViews / totalVideos) : null
          };
        }
      }

      if (!uploadsPlaylistId) {
        channelFailed = true;
        channelError = channelError || 'No uploads_playlist_id available';
      }

      // 2b. playlistItems.list -> 5 latest uploads
      let latestVideoIds = [];
      if (!channelFailed) {
        const plUrl = `https://www.googleapis.com/youtube/v3/playlistItems?part=snippet,contentDetails&playlistId=${uploadsPlaylistId}&maxResults=5&key=${ytKey}`;
        const plRes = await fetchWithRetry(plUrl, { method: 'GET' }, 'yt_playlistItems');
        if (plRes.quota) { quotaExhausted = true; break; }
        if (!plRes.ok) {
          channelFailed = true;
          channelError = plRes.error;
        } else {
          latestVideoIds = (plRes.json?.items || []).map(it => it.contentDetails?.videoId || it.snippet?.resourceId?.videoId).filter(Boolean);
        }
      }

      // 2c. Which videoIds are NEW?
      let newVideoIds = [];
      if (!channelFailed && latestVideoIds.length > 0) {
        const csv = latestVideoIds.map(v => `"${v}"`).join(',');
        const existUrl = `${supabaseUrl}/rest/v1/competitor_videos?competitor_channel_id=eq.${ch.id}&select=youtube_video_id&youtube_video_id=in.(${csv})`;
        const existRes = await fetch(existUrl, { method: 'GET', headers: sbHeaders });
        if (existRes.ok) {
          const existArr = await existRes.json();
          const existing = new Set((existArr || []).map(r => r.youtube_video_id));
          newVideoIds = latestVideoIds.filter(v => !existing.has(v));
        } else {
          // Safer to skip insert than risk duplicates
          newVideoIds = [];
          channelError = `existence check failed: HTTP ${existRes.status}`;
        }
      }

      // 2d. videos.list for new video details (1 call)
      let videoDetails = [];
      if (!channelFailed && newVideoIds.length > 0) {
        const vUrl = `https://www.googleapis.com/youtube/v3/videos?part=statistics,snippet,contentDetails&id=${newVideoIds.join(',')}&key=${ytKey}`;
        const vRes = await fetchWithRetry(vUrl, { method: 'GET' }, 'yt_videos');
        if (vRes.quota) { quotaExhausted = true; break; }
        if (vRes.ok) videoDetails = vRes.json?.items || [];
      }

      // 2e. Outlier denominator: avg_views_30d (refreshed stats) or fallback
      const avg30 = ch.avg_views_30d
        || statsPatch.avg_views_per_video
        || (ch.total_view_count && ch.total_video_count ? (ch.total_view_count / ch.total_video_count) : null);
      const denominator = (avg30 && avg30 > 0) ? avg30 : 1;

      // 2f. For each new video: compute metrics, insert competitor_videos, maybe alert
      for (const v of videoDetails) {
        const videoId = v.id;
        if (!videoId) continue;
        const title = (v.snippet?.title || '').slice(0, 500);
        const descSnippet = (v.snippet?.description || '').slice(0, 500);
        const thumb = v.snippet?.thumbnails?.high?.url || v.snippet?.thumbnails?.medium?.url || null;
        const publishedAt = v.snippet?.publishedAt || null;
        const durationSec = parseIsoDuration(v.contentDetails?.duration);
        const isShorts = durationSec > 0 && durationSec <= 60;
        const views = parseInt(v.statistics?.viewCount || '0', 10);
        const likes = parseInt(v.statistics?.likeCount || '0', 10);
        const comments = parseInt(v.statistics?.commentCount || '0', 10);
        const outlierRatio = Math.round((views / denominator) * 1000) / 1000;
        const isOutlier = outlierRatio >= 3.0 && views >= 1000;

        // Topic match: substring check against project topics
        let matchedTopicId = null;
        let topicMatch = false;
        const titleNorm = normalizeTitle(title);
        for (const t of topicCorpus) {
          if (!t.normalized) continue;
          if (titleNorm.includes(t.normalized) || t.normalized.includes(titleNorm)) {
            matchedTopicId = t.id;
            topicMatch = true;
            break;
          }
        }

        const row = {
          competitor_channel_id: ch.id,
          project_id: projectId,
          youtube_video_id: videoId,
          title,
          description_snippet: descSnippet,
          thumbnail_url: thumb,
          published_at: publishedAt,
          duration_seconds: durationSec || null,
          is_shorts: isShorts,
          views_at_discovery: views,
          views_7d: views,
          likes_count: likes,
          comments_count: comments,
          is_outlier: isOutlier,
          outlier_ratio: outlierRatio,
          topic_pattern_match: topicMatch,
          matched_topic_id: matchedTopicId
        };

        // Insert with return=representation so we get the id back for the alert FK
        let insertedVideoId = null;
        try {
          const insRes = await fetch(`${supabaseUrl}/rest/v1/competitor_videos`, {
            method: 'POST',
            headers: { ...sbHeaders, 'Prefer': 'return=representation' },
            body: JSON.stringify(row)
          });
          if (insRes.ok) {
            const arr = await insRes.json();
            insertedVideoId = Array.isArray(arr) && arr[0] ? arr[0].id : null;
            totalVideosInserted += 1;
          }
        } catch (_) { /* continue */ }

        // Outlier alert
        if (isOutlier) {
          try {
            const alertTitle = `🔥 ${ch.channel_name || 'Competitor'}: ${outlierRatio.toFixed(1)}x breakout`;
            const alertMsg = `"${title}" has ${views.toLocaleString()} views, ${outlierRatio.toFixed(1)}x this channel's 30-day average (${Math.round(denominator).toLocaleString()}).`;
            const alertRes = await fetch(`${supabaseUrl}/rest/v1/competitor_alerts`, {
              method: 'POST',
              headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
              body: JSON.stringify({
                project_id: projectId,
                competitor_channel_id: ch.id,
                competitor_video_id: insertedVideoId,
                alert_type: 'outlier_breakout',
                severity: outlierRatio >= 6.0 ? 'critical' : 'high',
                title: alertTitle.slice(0, 200),
                message: alertMsg,
                metadata: {
                  youtube_video_id: videoId,
                  channel_name: ch.channel_name,
                  outlier_ratio: outlierRatio,
                  views,
                  avg_views_30d: denominator,
                  is_shorts: isShorts
                }
              })
            });
            if (alertRes.ok) totalAlertsCreated += 1;
          } catch (_) { /* continue */ }
        }

        // Topic-match alert (separate, normal severity)
        if (topicMatch && !isOutlier) {
          try {
            const alertRes = await fetch(`${supabaseUrl}/rest/v1/competitor_alerts`, {
              method: 'POST',
              headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
              body: JSON.stringify({
                project_id: projectId,
                competitor_channel_id: ch.id,
                competitor_video_id: insertedVideoId,
                alert_type: 'topic_match',
                severity: 'normal',
                title: `🎯 ${ch.channel_name || 'Competitor'} covered your topic`,
                message: `"${title}" overlaps with one of your pipeline topics.`,
                metadata: {
                  youtube_video_id: videoId,
                  channel_name: ch.channel_name,
                  matched_topic_id: matchedTopicId,
                  views
                }
              })
            });
            if (alertRes.ok) totalAlertsCreated += 1;
          } catch (_) { /* continue */ }
        }
      }

      // 2g. Update channel stats (success path)
      if (!channelFailed) {
        try {
          await fetch(`${supabaseUrl}/rest/v1/competitor_channels?id=eq.${ch.id}`, {
            method: 'PATCH',
            headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
            body: JSON.stringify({
              ...statsPatch,
              last_checked_at: new Date().toISOString(),
              last_video_fetched_at: videoDetails.length > 0 ? new Date().toISOString() : ch.last_video_fetched_at,
              consecutive_fetch_failures: 0
            })
          });
        } catch (_) { /* continue */ }
        channelsProcessed += 1;
      } else {
        // Failure path: increment consecutive_fetch_failures, maybe deactivate
        const newFails = (ch.consecutive_fetch_failures || 0) + 1;
        const shouldDeactivate = newFails >= 5;
        try {
          await fetch(`${supabaseUrl}/rest/v1/competitor_channels?id=eq.${ch.id}`, {
            method: 'PATCH',
            headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
            body: JSON.stringify({
              consecutive_fetch_failures: newFails,
              is_active: shouldDeactivate ? false : true,
              last_checked_at: new Date().toISOString()
            })
          });
        } catch (_) { /* continue */ }

        // Log channel failure
        try {
          await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
            method: 'POST',
            headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
            body: JSON.stringify({
              project_id: projectId,
              topic_id: null,
              stage: 'competitor_monitor',
              scene_number: null,
              action: shouldDeactivate ? 'channel_deactivated' : 'channel_fetch_failed',
              status: 'error',
              duration_ms: Date.now() - channelStart,
              cost_usd: 0,
              retry_count: 0
            })
          });
        } catch (_) { }
      }
    } catch (e) {
      // Swallow per-channel errors so we don't abort the whole project
      try {
        await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
          method: 'POST',
          headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
          body: JSON.stringify({
            project_id: projectId,
            topic_id: null,
            stage: 'competitor_monitor',
            scene_number: null,
            action: 'channel_exception',
            status: 'error',
            duration_ms: Date.now() - channelStart,
            cost_usd: 0,
            retry_count: 0
          })
        });
      } catch (_) { }
    }
  }

  // Inter-batch delay
  if (i + channelBatchSize < channels.length && !quotaExhausted) {
    await sleep(1000);
  }
}

// 3. Summary log row for this project (daily run)
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: null,
      stage: 'competitor_monitor',
      scene_number: null,
      action: 'daily_summary',
      status: quotaExhausted ? 'partial_quota_exhausted' : 'success',
      duration_ms: Date.now() - runStart,
      cost_usd: 0,
      retry_count: 0
    })
  });
} catch (_) { }

return {
  json: {
    project_id: projectId,
    channels_total: channels.length,
    channels_processed: channelsProcessed,
    videos_inserted: totalVideosInserted,
    alerts_created: totalAlertsCreated,
    quota_exhausted: quotaExhausted,
    run_weekly_synthesis: data.run_weekly_synthesis,
    via_webhook: data.via_webhook,
    finished_at: new Date().toISOString()
  }
};

// Weekly synthesis: on Sunday UTC (or when forced), summarize the project's
// last 7 days of competitor activity via Claude Haiku 4.5 and UPSERT to
// competitor_intelligence. Skip otherwise.

const data = $input.item.json;
if (data.skipped || !data.run_weekly_synthesis || !data.project_id) {
  return $input.item;
}

const projectId = data.project_id;
const synthStart = Date.now();

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const anthropicKey = $env.ANTHROPIC_API_KEY;

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

// Compute this week's Sunday (the Sunday that just passed or today if Sunday UTC)
const now = new Date();
const dow = now.getUTCDay();
const weekOf = new Date(now);
weekOf.setUTCDate(now.getUTCDate() - dow);
const weekOfDate = weekOf.toISOString().slice(0, 10);
const sevenDaysAgo = new Date(now.getTime() - 7 * 86400000).toISOString();

// 1. Load last 7 days of competitor_videos for this project, join channel name
const vUrl = `${supabaseUrl}/rest/v1/competitor_videos?project_id=eq.${projectId}&first_seen_at=gte.${encodeURIComponent(sevenDaysAgo)}&select=title,published_at,views_at_discovery,outlier_ratio,is_outlier,is_shorts,competitor_channel_id,competitor_channels(channel_name)&order=views_at_discovery.desc&limit=100`;
const vRes = await fetch(vUrl, { method: 'GET', headers: sbHeaders });
if (!vRes.ok) {
  return {
    json: {
      ...data,
      weekly_synthesis_status: 'error',
      weekly_synthesis_error: `Fetch videos failed: HTTP ${vRes.status}`
    }
  };
}
const videos = await vRes.json();

if (!videos || videos.length === 0) {
  return {
    json: {
      ...data,
      weekly_synthesis_status: 'skipped_empty',
      week_of: weekOfDate
    }
  };
}

const outlierCount = videos.filter(v => v.is_outlier).length;
const uniqueChannels = new Set(videos.map(v => v.competitor_channel_id).filter(Boolean)).size;

// 2. Build Claude Haiku prompt
const videoList = videos.slice(0, 60).map(v => {
  const chName = v.competitor_channels?.channel_name || 'Unknown';
  const views = (v.views_at_discovery || 0).toLocaleString();
  const ratio = v.outlier_ratio ? `${v.outlier_ratio.toFixed(1)}x` : '';
  return `- [${chName}] "${(v.title || '').slice(0, 120)}" | ${views} views${ratio ? ' | ' + ratio : ''}${v.is_shorts ? ' | SHORT' : ''}`;
}).join('\n');

const prompt = `You are a competitive intelligence analyst for a YouTube creator. Analyze last week's competitor activity.

WEEK OF: ${weekOfDate}
CHANNELS ACTIVE: ${uniqueChannels}
VIDEOS PUBLISHED: ${videos.length}
OUTLIER BREAKOUTS (≥3x channel avg): ${outlierCount}

TOP VIDEOS (by views, up to 60):
${videoList}

TASK: Produce a weekly digest.
1. Group videos into 3-5 topic clusters by subject matter. For each: {cluster_name, video_count, avg_views}.
2. Identify 2-3 emerging patterns (new formats, breakthrough topics, aesthetic shifts). For each: {pattern, evidence, recommendation}.
3. Write a markdown digest under 400 words summarizing what this creator should pay attention to this week.

Return ONLY this JSON (no code fences, no other text):
{
  "top_topic_clusters": [{"cluster_name": "...", "video_count": 0, "avg_views": 0}],
  "emerging_patterns": [{"pattern": "...", "evidence": "...", "recommendation": "..."}],
  "summary_markdown": "..."
}`;

// 3. Claude Haiku 4.5 with inline backoff
const MAX_RETRIES = 4;
let retryCount = 0;
let parsed = null;
let claudeErr = null;

for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
  try {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 2000,
        messages: [{ role: 'user', content: prompt }]
      })
    });
    if (res.ok) {
      const body = await res.json();
      const text = body.content?.[0]?.text || '';
      const clean = text.replace(/```json|```/g, '').trim();
      try { parsed = JSON.parse(clean); }
      catch {
        const m = clean.match(/\{[\s\S]*\}/);
        if (m) { try { parsed = JSON.parse(m[0]); } catch {} }
      }
      if (parsed) break;
      claudeErr = 'parse_failed';
      break;
    }
    const errBody = await res.text();
    claudeErr = `HTTP ${res.status}: ${errBody.slice(0, 200)}`;
    if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
  } catch (e) { claudeErr = e.message; }
  if (attempt < MAX_RETRIES) {
    retryCount += 1;
    await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
}

if (!parsed) {
  return {
    json: {
      ...data,
      weekly_synthesis_status: 'claude_failed',
      weekly_synthesis_error: claudeErr,
      week_of: weekOfDate
    }
  };
}

// 4. UPSERT competitor_intelligence on conflict (project_id, week_of)
const upsertRow = {
  project_id: projectId,
  week_of: weekOfDate,
  channels_analyzed: uniqueChannels,
  videos_analyzed: videos.length,
  outlier_breakouts_count: outlierCount,
  top_topic_clusters: parsed.top_topic_clusters || [],
  emerging_patterns: parsed.emerging_patterns || [],
  summary_markdown: String(parsed.summary_markdown || '').slice(0, 8000),
  generated_by: 'claude-haiku-4-5-20251001'
};

try {
  await fetch(`${supabaseUrl}/rest/v1/competitor_intelligence?on_conflict=project_id,week_of`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'resolution=merge-duplicates,return=minimal' },
    body: JSON.stringify(upsertRow)
  });
} catch (_) { }

// 5. Log synthesis completion (Haiku 4.5 weekly synthesis ~ $0.005)
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: null,
      stage: 'competitor_monitor',
      scene_number: null,
      action: 'weekly_synthesis',
      status: 'success',
      duration_ms: Date.now() - synthStart,
      cost_usd: 0.005,
      retry_count: retryCount
    })
  });
} catch (_) { }

return {
  json: {
    ...data,
    weekly_synthesis_status: 'success',
    week_of: weekOfDate,
    clusters_found: (parsed.top_topic_clusters || []).length,
    patterns_found: (parsed.emerging_patterns || []).length
  }
};

// Aggregate across all processed projects.
const items = $input.all().map(i => i.json);
const meaningful = items.filter(j => !j.skipped);

if (meaningful.length === 0) {
  return [{
    json: {
      success: true,
      projects_processed: 0,
      message: items[0]?.reason || 'No projects to process'
    }
  }];
}

const totalVideos = meaningful.reduce((s, b) => s + (b.videos_inserted || 0), 0);
const totalAlerts = meaningful.reduce((s, b) => s + (b.alerts_created || 0), 0);
const totalChannels = meaningful.reduce((s, b) => s + (b.channels_processed || 0), 0);
const quota = meaningful.some(b => b.quota_exhausted);
const weeklySynths = meaningful.filter(b => b.weekly_synthesis_status === 'success').length;
const viaWebhook = meaningful.some(b => b.via_webhook);

return [{
  json: {
    success: true,
    projects_processed: meaningful.length,
    channels_processed: totalChannels,
    videos_inserted: totalVideos,
    alerts_created: totalAlerts,
    weekly_syntheses_generated: weeklySynths,
    quota_exhausted: quota,
    via_webhook: viaWebhook,
    finished_at: new Date().toISOString(),
    per_project: meaningful.map(b => ({
      project_id: b.project_id,
      channels_processed: b.channels_processed || 0,
      videos_inserted: b.videos_inserted || 0,
      alerts_created: b.alerts_created || 0,
      weekly_synthesis_status: b.weekly_synthesis_status || 'not_run',
      quota_exhausted: b.quota_exhausted || false
    }))
  }
}];
